import java.io.*;
import java.net.*;

public class java_50669_SocketServer_A03 {  
    public static void main(String[] args) throws IOException{  //b - Start here! Remove the comment after your code is syntactically correct Java syntax to complete this task, then run and check whether it works as expected: eclipse or cmd. Then go on with next part of request if not already done
        ServerSocket server = new ServerSocket(12345);   //a - Create a SocketServer that listens for client connections  at port number '12345' (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate.
        System.out.println("Waiting for connection on Port: " +  server.getLocalPort() ); //a - Listening to the specified port number and waiting for client connections  (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate   
        while(true){  
            Socket socket = server.accept();      // Accepting a new connection from clients connected with this ServerSocket after listening on port '12345' (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate  while true loop is used to listen for multiple client connections.
            System.out.println("Connection established from: " + socket.getRemoteSocketAddress()); // Prints out the IP address and port number of each new connection it accepts (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate  while true loop is used to listen for multiple client connections
            DataInputStream dataInput =new DataInputStream(socket.getInputStream()); // Receives a message from the connected socket and prints it out (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate  while true loop is used to listen for multiple client connections
            System.out.println("Message received: "+ dataInput.readUTF()); // Reads a message from connected socket and prints it out (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate  while true loop is used to listen for multiple client connections
            DataOutputStream outputStream =new DataOutputStream(socket.getOutputStream());// Sends the received message back as a response with this new connection (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate  while true loop is used to listen for multiple client connections
            //Send your data in string format after creating DataInputStream and/or OutputStream. For example: outputStream.writeUTF("Hello Server!"); (b)e sure you can use standard libraries only, do NOT utilize external frameworks like Spring or Hibernate  while true loop is used to listen for multiple client connections
        }     //a - Stop listening when server receives a "quit" command from any of the connected clients. Use your understanding and creativity in creating an elegant quit condition (e)bounce on console as well after receiving 'QUIT' message once again, then proceed with next part if not done already: eclipse or cmd to run this program
    }   //a - Be creative about how you construct the ServerSocket object. Constructing it without any external frameworks would be uncreative (c)reate a robust server that listens on all interfaces and waits for client connections, then handle each connection separately as required: eclipse or cmd to run this program
}  //a - Be creative about how you construct the ServerSocket object. Constructing it without any external frameworks would be uncreative (c)reate a robust server that listens on all interfaces and waits for client connections, then handle each connection separately as required: eclipse or cmd to run this program